package phoenix.geocomply.infrastructure.xml

import cats.data.Validated.Valid
import org.scalatest.matchers.should.Matchers
import org.scalatest.wordspec.AnyWordSpecLike

import phoenix.core.ScalaObjectUtils._
import phoenix.core.TimeUtils._
import phoenix.core.XmlUtils._
import phoenix.geocomply.domain.License.Expiration
import phoenix.geocomply.domain.License.GeoComplyLicense
import phoenix.geocomply.domain.License.LicenseKey
import phoenix.geocomply.infrastructure.xml.LicenseKeyResponseXmlReader._
import phoenix.support.FileSupport

final class LicenseKeyResponseXmlReaderSpec extends AnyWordSpecLike with Matchers with FileSupport {

  s"${LicenseKeyResponseXmlReader.simpleObjectName}" should {

    "read a valid license key response" in {
      licenseKeyResponseXml.convertTo[GeoComplyLicense] shouldBe expectedLicenseKeyResponse
    }
  }

  private val licenseKeyResponseXml =
    stringFromResource(baseDir = "data/geocomply", fileName = "license-key-response.xml").parseXml

  private val expectedLicenseKeyResponse = Valid(
    GeoComplyLicense(
      LicenseKey(
        ""),
      Expiration("2021-01-18T12:51:30Z".toUtcOffsetDateTime)))
}
